    return text.strip()

def get_html():
    now = datetime.now().strftime('%Y-%m-%d %H:%M:%S')

    # Worker 状态
    workers_html = ""
    worker_data = [
        ("技术员", 18811, "👨‍💻", "负责代码开发、调试、重构"),
