                    content = log
                    activity_html += f'<div class="log-entry"><span class="log-time">{time_part}</span><span class="log-content">{content}</span></div>'
                else:
                    activity_html += f'<div class="log-entry">{log}</div>'
    else:
        activity_html = '<div style="color:#666;text-align:center;padding:20px">暂无新消息</div>'

    # 系统状态
    containers = run_cmd("docker ps --filter 'name=openclaw-' --format '{{.Names}}\\t{{.Status}}' | grep -v redis")
    containers_html = ""
    if containers:
        for line in containers.split('\n'):
            if '\t' in line:
                cname, cstatus = line.split('\t', 1)
                cname = cname.replace('openclaw-', '')
                cstatus = cstatus.split(' ')[0]
                containers_html += f'<div class="info-row"><span>🐳 {cname}</span><span class="badge badge-ok">{cstatus}</span></div>'

    circuit_check = run_cmd("pm2 logs master-nanchaoyi --lines 5 --nostream 2>&1 | grep -c 'circuit.open' || echo 0").strip()
