        </div>
    </div>

    <div class="circuit-status">
        <span class="circuit-icon">{circuit_icon}</span>
        <span class="circuit-text">熔断器：{circuit_text}</span>
    </div>
</section>

<section class="section">
    <div class="section-title">🐳 容器监控</div>
    {containers_html if containers_html else '<div style="color:#666;text-align:center;padding:20px">无容器运行</div>'}
</section>

<section class="section">
    <div class="section-title">📋 任务队列</div>
    {tasks_html}
</section>

<section class="section">
    <div class="section-title">⚙️ PM2 进程</div>
    {pm2_html if pm2_html else '<div style="color:#666;text-align:center;padding:20px">无 PM2 进程</div>'}
</section>

<section class="section">
    <div class="section-title">📝 实时日志</div>
    <div style="max-height:400px;overflow-y:auto;">
    {logs_html}
    </div>
</section>

<footer style="text-align:center;padding:30px 0;color:#444;font-size:13px;border-top:1px solid rgba(255,255,255,0.05);margin-top:30px;">
    OpenClaw 监控系统 v2.0 · Powered by Python
</footer>
</div>
</body>
</html>'''

class Handler(http.server.BaseHTTPRequestHandler):
    def do_GET(self):
        self.send_response(200)
        self.send_header('Content-type', 'text/html; charset=utf-8')
        self.end_headers()
        self.wfile.write(get_html().encode('utf-8'))
    def log_message(self, format, *args):
        pass

if __name__ == "__main__":
    socketserver.TCPServer.allow_reuse_address = True
    with socketserver.TCPServer(("", PORT), Handler) as httpd:
        print(f"监控网页已启动：http://0.0.0.0:{PORT}")
        httpd.serve_forever()

