        latency_badge = f'<div style="margin-top:8px"><span style="background:rgba(0,255,136,0.1);color:#00ff88;padding:2px 8px;border-radius:4px;font-size:11px">{latency}秒</span></div>' if ok else ""
        workers_html += f'''
