body {{ font-family: 'SF Pro Display', -apple-system, BlinkMacSystemFont, 'Microsoft YaHei', sans-serif; background: radial-gradient(ellipse at top, #1a1a2e 0%, var(--bg-primary) 100%); color: var(--text-primary); min-height: 100vh; overflow-x: hidden; }}
body::before {{ content: ''; position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: url("data:image/svg+xml,%3Csvg viewBox='0 0 400 400' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='400' height='400' filter='url(%23noise)' opacity='0.05'/%3E%3C/svg%3E"); pointer-events: none; z-index: -1; }}

.container {{ max-width: 1400px; margin: 0 auto; padding: 30px; }}

/* Header */
header {{ text-align: center; padding: 40px 0; margin-bottom: 40px; position: relative; }}
header::after {{ content: ''; position: absolute; bottom: 0; left: 50%; transform: translateX(-50%); width: 200px; height: 1px; background: linear-gradient(90deg, transparent, var(--accent-cyan), transparent); }}
