.progress-fill::after {{ content: ''; position: absolute; top: 0; right: 0; width: 3px; height: 100%; background: rgba(255, 255, 255, 0.5); }}
.progress-value {{ font-size: 12px; font-weight: 600; min-width: 45px; text-align: right; }}

/* Task Items */
.task-item {{ display: flex; align-items: center; padding: 16px 20px; background: rgba(0, 0, 0, 0.2); border-radius: 14px; margin-bottom: 10px; transition: all 0.3s ease; }}
