.task-item:hover .task-item-arrow {{ transform: translateX(5px); color: var(--accent-cyan); }}

/* Circuit */
.circuit-wrap {{ display: flex; align-items: center; gap: 20px; padding: 20px; background: rgba(0, 0, 0, 0.2); border-radius: 16px; border-left: 4px solid; }}
.circuit-icon {{ font-size: 36px; }}
