/* Logs */
.log-container {{ max-height: 400px; overflow-y: auto; }}
.log-container::-webkit-scrollbar {{ width: 6px; }}
.log-container::-webkit-scrollbar-track {{ background: rgba(0, 0, 0, 0.2); border-radius: 3px; }}
.log-container::-webkit-scrollbar-thumb {{ background: rgba(255, 255, 255, 0.1); border-radius: 3px; }}
.log-entry {{ display: flex; align-items: flex-start; gap: 12px; padding: 14px 16px; background: rgba(0, 0, 0, 0.25); border-radius: 12px; margin-bottom: 10px; font-family: 'JetBrains Mono', monospace; font-size: 12px; transition: all 0.3s ease; }}
.log-entry:hover {{ transform: translateX(5px); background: rgba(0, 0, 0, 0.35); }}
.log-dot {{ width: 8px; height: 8px; border-radius: 50%; margin-top: 4px; flex-shrink: 0; }}
.log-info .log-dot {{ background: var(--accent-cyan); }}
.log-warn .log-dot {{ background: var(--accent-yellow); }}
.log-error .log-dot {{ background: var(--accent-red); }}
.log-text {{ color: var(--text-secondary); word-break: break-word; line-height: 1.6; }}
.log-info .log-text {{ color: #aaa; }}
.log-warn .log-text {{ color: var(--accent-yellow); }}
.log-error .log-text {{ color: var(--accent-red); }}
.log-empty {{ text-align: center; color: var(--text-secondary); padding: 40px; }}

/* Footer */
footer {{ text-align: center; padding: 30px; color: var(--text-secondary); font-size: 13px; border-top: 1px solid var(--border-color); margin-top: 40px; }}

/* Responsive */
@media (max-width: 768px) {{
    .container {{ padding: 15px; }}
    h1 {{ font-size: 26px; }}
    .workers-grid {{ grid-template-columns: 1fr; }}
    .stats-grid {{ grid-template-columns: repeat(2, 1fr); }}
