#!/usr/bin/env python3
"""OpenClaw 监控网页 - 专业版"""

import http.server
import socketserver
import subprocess
import re
import json
import os
from datetime import datetime
from collections import deque

PORT = 18080
HISTORY_FILE = "/root/.openclaw/logs/monitor-history.json"

# 内存历史记录（最多 100 条）
history = deque(maxlen=100)

def load_history():
    global history
    try:
        if os.path.exists(HISTORY_FILE):
            with open(HISTORY_FILE, 'r') as f:
                data = json.load(f)
                history = deque(data[-100:], maxlen=100)
    except:
        pass

def save_history():
    try:
        os.makedirs(os.path.dirname(HISTORY_FILE), exist_ok=True)
        with open(HISTORY_FILE, 'w') as f:
            json.dump(list(history), f)
    except:
        pass

load_history()

def run_cmd(cmd):
    try:
        result = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=5)
        return result.stdout.strip()
    except:
        return ""

def clean_ansi(text):
    text = re.sub(r'\x1B\[[0-9;]*[a-zA-Z]', '', text)
    text = re.sub(r'\x1B[@-Z\\-_]', '', text)
    return text.strip()

def html_escape(text):
    if not text:
        return ""
    return text.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')

def get_worker_info(port):
    """获取 Worker 详细信息"""
    info = {"ok": False, "latency": "0", "http_code": "000"}
    try:
        # HTTP 检查
        code = run_cmd(f"curl -s -o /dev/null -w '%{{http_code}}' --connect-timeout 2 http://127.0.0.1:{port}/.well-known/agent-card.json")
        latency = run_cmd(f"curl -s -o /dev/null -w '%{{time_total}}' --connect-timeout 2 http://127.0.0.1:{port}/.well-known/agent-card.json")
        info["http_code"] = code or "000"
        info["latency"] = latency or "0"
        info["ok"] = code == "200"

        # 获取 agent-card 内容
        if info["ok"]:
            card = run_cmd(f"curl -s http://127.0.0.1:{port}/.well-known/agent-card.json")
            if card:
                try:
                    card_data = json.loads(card)
                    info["name"] = card_data.get("name", "")
                    info["version"] = card_data.get("version", "")
                except:
                    pass
    except:
        pass
    return info

def get_container_details():
    """获取容器详细信息"""
    containers = []
    result = run_cmd("docker ps --filter 'name=openclaw-' --format '{{.Names}}\\t{{.Status}}\\t{{.CPUPerc}}\\t{{.MemPerc}}' | grep -v redis")
    if result:
        for line in result.split('\n'):
            parts = line.split('\t')
            if len(parts) >= 4:
                name = parts[0].replace('openclaw-', '')
                status = parts[1]
                cpu = parts[2].rstrip('%')
                mem = parts[3].rstrip('%')
                containers.append({
                    "name": name,
                    "status": status.split(' ')[0],
                    "cpu": cpu,
                    "mem": mem
                })
    return containers

def get_task_details():
    """获取任务队列详情"""
    tasks = []
    for worker_type, name in [("tech", "技术员"), ("ops", "运营官"), ("image", "设计师"), ("naming", "南南")]:
        task_dir = f"/root/.openclaw/{worker_type}"
        try:
            result = run_cmd(f"docker exec openclaw-{worker_type} ls -lt /root/.openclaw/a2a-tasks/ 2>/dev/null | head -5")
            task_files = []
            if result:
                for line in result.split('\n'):
                    if '.json' in line:
                        parts = line.split()
                        if len(parts) >= 8:
                            filename = parts[-1]
                            date = f"{parts[1]} {parts[2]} {parts[3]}"
                            task_files.append({"name": filename, "time": date})
            tasks.append({"name": name, "count": len(task_files), "files": task_files})
        except:
            tasks.append({"name": name, "count": 0, "files": []})
    return tasks

def get_system_stats():
    """获取系统统计"""
    stats = {
        "cpu": "0",
        "mem_used": "0",
        "mem_total": "0",
        "mem_percent": 0,
        "disk_used": "0",
        "disk_total": "0",
        "disk_percent": 0,
        "uptime": "0"
    }

    # CPU
    cpu = run_cmd("top -bn1 | grep 'Cpu(s)' | awk '{print $2}' | cut -d'%' -f1")
    stats["cpu"] = cpu or "0"

    # 内存
    mem_info = run_cmd("free -m | awk 'NR==2{printf \"%d %d %.0f\", $3, $2, $3/$2*100}'")
    if mem_info:
        parts = mem_info.split()
        if len(parts) >= 3:
            stats["mem_used"] = parts[0]
            stats["mem_total"] = parts[1]
            stats["mem_percent"] = float(parts[2])

    # 磁盘
    disk_info = run_cmd("df -h / | awk 'NR==2{printf \"%s %s %s\", $3, $2, $5}' | tr -d '%'")
    if disk_info:
        parts = disk_info.split()
        if len(parts) >= 3:
            stats["disk_used"] = parts[0]
            stats["disk_total"] = parts[1]
            stats["disk_percent"] = float(parts[2])

    # 运行时间
    uptime_info = run_cmd("uptime -p")
    stats["uptime"] = uptime_info.replace("up ", "") if uptime_info else "未知"

    return stats

def get_pm2_status():
    """获取 PM2 进程状态"""
    pm2_apps = []
    result = run_cmd("pm2 list --no-color 2>/dev/null")
    if result:
        lines = result.split('\n')
        for line in lines:
            if 'online' in line.lower() or 'stopped' in line.lower() or 'errored' in line.lower():
                parts = line.split()
                if len(parts) >= 8:
                    pm2_apps.append({
                        "name": parts[1] if len(parts) > 1 else "unknown",
                        "status": parts[3] if len(parts) > 3 else "unknown",
                        "cpu": parts[5] if len(parts) > 5 else "0%",
                        "mem": parts[6] if len(parts) > 6 else "0B"
                    })
    return pm2_apps

def get_circuit_status():
    """获取熔断器状态"""
    result = run_cmd("pm2 logs master-nanchaoyi --lines 10 --nostream 2>&1 | grep -c 'circuit.open' || echo 0")
    count = int(result.strip()) if result.strip().isdigit() else 0
    return {"open": count > 0, "count": count}

def get_recent_logs():
    """获取最近日志"""
    logs = []
    result = run_cmd("pm2 logs master-nanchaoyi --lines 20 --nostream 2>&1 | grep -E 'feishu|dispatch|circuit|error' | tail -20")
    if result:
        for line in result.split('\n'):
            line = clean_ansi(line).strip()
            if line:
                logs.append(html_escape(line))
    return logs

def generate_mini_chart(values, width=100, height=30, color="#00d9ff"):
    """生成迷你图表 SVG"""
    if not values or len(values) < 2:
        return ""

    max_val = max(values) if max(values) > 0 else 100
    min_val = 0
    step = width / (len(values) - 1) if len(values) > 1 else width

    points = []
    for i, v in enumerate(values):
        x = i * step
        y = height - (v - min_val) / (max_val - min_val) * height if max_val != min_val else height / 2
        points.append(f"{x:.1f},{y:.1f}")

    path = "M " + " L ".join(points)
    return f'<svg width="{width}" height="{height}" style="display:block;margin:0 auto"><path d="{path}" fill="none" stroke="{color}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>'

def get_html():
    now = datetime.now().strftime('%Y-%m-%d %H:%M:%S')

    # 收集 Worker 状态
    workers = []
    worker_config = [
        ("技术员", 18811, "👨‍💻", "代码开发、调试、重构", "#00d9ff"),
        ("运营官", 18813, "📝", "内容创作、文案、策划", "#00ff88"),
        ("设计师", 18815, "🎨", "图像处理、设计优化", "#ff6b6b"),
        ("南南", 18817, "🤖", "命名、翻译、咨询", "#ffd93d")
    ]

    for name, port, icon, desc, color in worker_config:
        info = get_worker_info(port)
        workers.append({
            "name": name,
            "port": port,
            "icon": icon,
            "desc": desc,
            "color": color,
            "ok": info["ok"],
            "latency": info["latency"],
            "http_code": info["http_code"]
        })

    # 保存历史记录
    all_ok = all(w["ok"] for w in workers)
    stats = get_system_stats()
    history.append({
        "time": now,
        "ok": all_ok,
        "cpu": float(stats["cpu"]),
        "mem": stats["mem_percent"],
        "workers_up": sum(1 for w in workers if w["ok"])
    })
    save_history()

    # Worker 卡片 HTML
    workers_html = ""
    for w in workers:
        status_color = w["color"] if w["ok"] else "#ff4444"
        status_text = "✓ 运行中" if w["ok"] else "✗ 已断开"
        latency_display = f'<div class="latency-badge" style="margin-top:8px"><span style="background:{w["color"]}22;color:{w["color"]};padding:3px 10px;border-radius:6px;font-size:12px">{w["latency"]}秒</span></div>' if w["ok"] else ""
        workers_html += f'''
        <div class="worker-card" style="border-left:4px solid {status_color}">
            <div style="font-size:48px;margin-bottom:12px;text-shadow:0 0 20px {status_color}44">{w["icon"]}</div>
            <div style="font-size:20px;color:#fff;font-weight:bold;margin-bottom:6px">{w["name"]}</div>
            <div style="font-size:13px;color:#666;margin-bottom:15px;line-height:1.5">{w["desc"]}</div>
            <div style="display:inline-block;padding:8px 24px;border-radius:24px;font-size:14px;font-weight:bold;background:{status_color}22;color:{status_color};border:1px solid {status_color}44">{status_text}</div>
            {latency_display}
            <div style="margin-top:12px;font-size:11px;color:#444">端口：{w["port"]}</div>
        </div>'''

    # 容器详情
    containers = get_container_details()
    containers_html = ""
    if containers:
        for c in containers:
            cpu_color = "#00ff88" if float(c["cpu"]) < 50 else "#ffaa00" if float(c["cpu"]) < 80 else "#ff4444"
            containers_html += f'''
            <div class="container-row">
                <div class="container-info">
                    <span class="container-icon">🐳</span>
                    <span class="container-name">{c["name"]}</span>
                    <span class="container-status" style="color:{c["color"] if "color" in c else "#00ff88"}">{c["status"]}</span>
                </div>
                <div class="container-stats">
                    <div class="stat-mini"><span style="color:{cpu_color}">CPU {c["cpu"]}%</span></div>
                    <div class="stat-mini"><span style="color:#00d9ff">MEM {c["mem"]}%</span></div>
                </div>
            </div>'''

    # 任务队列
    tasks = get_task_details()
    tasks_html = ""
    for t in tasks:
        task_color = "#ffaa00" if t["count"] > 5 else "#00ff88"
        tasks_html += f'''
        <div class="task-row">
            <span class="task-icon">{t["name"][:1]}</span>
