            <span class="task-count" style="color:{task_color}">{t["count"]} 个任务</span>
        </div>'''

    # 系统统计
    cpu_chart = generate_mini_chart([h["cpu"] for h in history], 120, 40, "#ff6b6b")
    mem_chart = generate_mini_chart([h["mem"] for h in history], 120, 40, "#00d9ff")

    # PM2 状态
    pm2_apps = get_pm2_status()
    pm2_html = ""
    if pm2_apps:
        for app in pm2_apps:
            pm2_html += f'<div class="pm2-row"><span class="pm2-name">{html_escape(app["name"])}</span><span class="pm2-status status-{app["status"].lower()}">{app["status"]}</span><span class="pm2-stat">CPU:{app["cpu"]}</span><span class="pm2-stat">MEM:{app["mem"]}</span></div>'

    # 熔断器
    circuit = get_circuit_status()
