            elif is_running and not is_a2a_ok:
                status_icon = "🟡"
                status_text = "失联"
                color = "#ffaa00"
            else:
                status_icon = "🔴"
                status_text = "异常"
                color = "#ff4444"

        # 最后消息时间
        last_msg = c.get("last_msg", "")
        last_msg_display = ""
        if last_msg:
            try:
                msg_time = datetime.strptime(last_msg, '%Y-%m-%dT%H:%M:%S')
                diff = (datetime.now() - msg_time).seconds
                if diff < 60:
                    last_msg_display = f"{diff}秒前"
                elif diff < 3600:
                    last_msg_display = f"{diff//60}分钟前"
                else:
                    last_msg_display = f"{diff//3600}小时前"
            except:
