            </div>
            {f'<div class="container-last-msg"><span class="msg-label">最后消息</span><span class="msg-time">{last_msg_display}</span></div>' if last_msg and not c.get('is_redis') and not c.get('is_pm2') else ''}
        </div>'''

    # 告警列表
    alerts_html = ""
