                <span class="alert-msg">{html_escape(a["msg"])}</span>
            </div>'''
    else:
        alerts_html = '<div class="alerts-empty">✓ 暂无异常</div>'

    # 日志
    logs = get_recent_logs()
    logs_html = ""
    for log in logs[-15:]:
        log_class = "log-error" if "error" in log.lower() or "Error" in log else "log-warn" if "circuit" in log or "timeout" in log else "log-info"
        logs_html += f'<div class="log-entry {log_class}">{log}</div>'

    # 图表
    cpu_chart = generate_svg_chart([h["cpu"] for h in history[-30:]], 180, 50, "#ff6b6b")
    mem_chart = generate_svg_chart([h["mem"] for h in history[-30:]], 180, 50, "#00d9ff")

    uptime_result = run_cmd("uptime -p")
    uptime_display = uptime_result.replace("up ", "") if uptime_result else "未知"
    load_result = run_cmd("uptime | awk -F'load average:' '{print $2}' | awk -F',' '{print $1}'")
    load_display = load_result.strip() if load_result else "0"

    return f'''<!DOCTYPE html>
