            </div>
        </div>
        <div style="text-align:center;color:var(--text-secondary);font-size:13px">
            系统运行：{uptime_display} · 负载：{load_display}
        </div>
    </section>

    <section class="section">
        <div class="section-title"><span class="section-title-icon">🐳</span>容器状态总览</div>
        <div class="containers-grid">
