#!/usr/bin/env python3
"""OpenClaw 监控网页 - 终极版"""

import http.server
import socketserver
import subprocess
import re
import json
import os
from datetime import datetime
from collections import deque

PORT = 18080
HISTORY_FILE = "/root/.openclaw/logs/monitor-history.json"

history = deque(maxlen=120)

def load_history():
    global history
    try:
        if os.path.exists(HISTORY_FILE):
            with open(HISTORY_FILE, 'r') as f:
                data = json.load(f)
                history = deque(data[-120:], maxlen=120)
    except:
        pass

def save_history():
    try:
        os.makedirs(os.path.dirname(HISTORY_FILE), exist_ok=True)
        with open(HISTORY_FILE, 'w') as f:
            json.dump(list(history), f)
    except:
        pass

load_history()

def run_cmd(cmd):
    try:
        result = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=5)
        return result.stdout.strip()
    except:
        return ""

def clean_ansi(text):
    text = re.sub(r'\x1B\[[0-9;]*[a-zA-Z]', '', text)
    text = re.sub(r'\x1B[@-Z\\-_]', '', text)
    return text.strip()

def html_escape(text):
    if not text:
        return ""
    return text.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')

def get_worker_info(port):
    info = {"ok": False, "latency": "0", "http_code": "000"}
    try:
        code = run_cmd(f"curl -s -o /dev/null -w '%{{http_code}}' --connect-timeout 2 http://127.0.0.1:{port}/.well-known/agent-card.json")
        latency = run_cmd(f"curl -s -o /dev/null -w '%{{time_total}}' --connect-timeout 2 http://127.0.0.1:{port}/.well-known/agent-card.json")
        info["http_code"] = code or "000"
        info["latency"] = latency or "0"
        info["ok"] = code == "200"
    except:
        pass
    return info

def get_container_details():
    containers = []
    result = run_cmd("docker ps --filter 'name=openclaw-' --format '{{.Names}}\\t{{.Status}}\\t{{.CPUPerc}}\\t{{.MemPerc}}' | grep -v redis")
    if result:
        for line in result.split('\n'):
            parts = line.split('\t')
            if len(parts) >= 4:
                name = parts[0].replace('openclaw-', '')
                status = parts[1]
                cpu = parts[2].rstrip('%').replace(' ', '')
                mem = parts[3].rstrip('%').replace(' ', '')
                try:
                    cpu = float(cpu) if cpu else 0
                    mem = float(mem) if mem else 0
                except:
                    cpu, mem = 0, 0
                containers.append({"name": name, "status": status.split(' ')[0], "cpu": cpu, "mem": mem})
    return containers

def get_task_details():
    tasks = []
    for worker_type, name in [("tech", "技术员"), ("ops", "运营官"), ("image", "设计师"), ("naming", "南南")]:
        try:
            result = run_cmd(f"docker exec openclaw-{worker_type} ls -lt /root/.openclaw/a2a-tasks/ 2>/dev/null | head -5")
            task_files = []
            if result:
                for line in result.split('\n'):
                    if '.json' in line:
                        parts = line.split()
                        if len(parts) >= 8:
                            filename = parts[-1]
                            date = f"{parts[1]} {parts[2]} {parts[3]}"
                            task_files.append({"name": filename, "time": date})
            tasks.append({"name": name, "count": len(task_files), "files": task_files})
        except:
            tasks.append({"name": name, "count": 0, "files": []})
    return tasks

def get_system_stats():
    stats = {"cpu": "0", "mem_used": "0", "mem_total": "0", "mem_percent": 0, "disk_used": "0", "disk_total": "0", "disk_percent": 0, "uptime": "0", "load": "0"}

    cpu = run_cmd("top -bn1 | grep 'Cpu(s)' | awk '{print $2}' | cut -d'%' -f1")
    stats["cpu"] = cpu or "0"

    mem_info = run_cmd("free -m | awk 'NR==2{printf \"%d %d %.0f\", $3, $2, $3/$2*100}'")
    if mem_info:
        parts = mem_info.split()
        if len(parts) >= 3:
            stats["mem_used"], stats["mem_total"], stats["mem_percent"] = parts[0], parts[1], float(parts[2])

    disk_info = run_cmd("df -h / | awk 'NR==2{printf \"%s %s %s\", $3, $2, $5}' | tr -d '%'")
    if disk_info:
        parts = disk_info.split()
        if len(parts) >= 3:
            stats["disk_used"], stats["disk_total"], stats["disk_percent"] = parts[0], parts[1], float(parts[2])

    uptime_info = run_cmd("uptime -p")
    stats["uptime"] = uptime_info.replace("up ", "") if uptime_info else "未知"

    load_info = run_cmd("uptime | awk -F'load average:' '{print $2}' | awk -F',' '{print $1}'")
    stats["load"] = load_info.strip() if load_info else "0"

    return stats

def get_circuit_status():
    result = run_cmd("pm2 logs master-nanchaoyi --lines 10 --nostream 2>&1 | grep -c 'circuit.open' || echo 0")
    count = int(result.strip()) if result.strip().isdigit() else 0
    return {"open": count > 0, "count": count}

def get_recent_logs():
    logs = []
    result = run_cmd("pm2 logs master-nanchaoyi --lines 30 --nostream 2>&1 | grep -E 'feishu|dispatch|circuit|error|Error' | tail -30")
    if result:
        for line in result.split('\n'):
            line = clean_ansi(line).strip()
            if line:
                logs.append(html_escape(line))
    return logs

def generate_svg_chart(values, width=200, height=60, color="#00d9ff", fill=False):
    if not values or len(values) < 2:
        return ""

    max_val = max(values) if max(values) > 0 else 1
    min_val = min(values) if min(values) < max_val else 0
    range_val = max_val - min_val if max_val != min_val else 1

    step = width / (len(values) - 1)
    points = []
    area_points = []

    for i, v in enumerate(values):
        x = i * step
        y = height - ((v - min_val) / range_val * (height - 10) + 5)
        points.append(f"{x:.1f},{y:.1f}")
        area_points.append(f"{x:.1f},{y:.1f}")

    path = "M " + " L ".join(points)

    if fill:
        area_points.append(f"{width},{height}")
        area_points.append(f"0,{height}")
        area_path = "M " + " L ".join(area_points) + " Z"
        return f'<svg width="{width}" height="{height}" viewBox="0 0 {width} {height}" preserveAspectRatio="none"><path d="{area_path}" fill="{color}22"/><path d="{path}" fill="none" stroke="{color}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>'

    return f'<svg width="{width}" height="{height}" viewBox="0 0 {width} {height}" preserveAspectRatio="none"><path d="{path}" fill="none" stroke="{color}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>'

def get_html():
    now = datetime.now().strftime('%Y-%m-%d %H:%M:%S')

    workers = []
    worker_config = [
        ("技术员", 18811, "👨‍💻", "代码开发 · 调试 · 重构", "#00d9ff"),
