                <div class="progress-wrap"><span class="progress-label">CPU</span><div class="progress-bar"><div class="progress-fill" style="width:{c["cpu"]}%;background:{cpu_color}"></div></div><span class="progress-value" style="color:{cpu_color}">{c["cpu"]}%</span></div>
                <div class="progress-wrap"><span class="progress-label">MEM</span><div class="progress-bar"><div class="progress-fill" style="width:{c["mem"]}%;background:#00d9ff"></div></div><span class="progress-value" style="color:#00d9ff">{c["mem"]}%</span></div>
